mapper.insert:
create table member_extend_field (
id bigint(64) primary key auto_increment COMMENT '主键',
member_id bigint(64) unsigned COMMENT '关联会员',

    ${field.colName} ${field.colType} COMMENT #{field.colTitle}

) COMMENT '会员扩展字段'

mapper.select:
SELECT
t.*
FROM
member_extend_field_config t
WHERE
1 = 1

    AND t.id = #{memberExtendFieldConfigEntity.id}


    AND t.col_title like concat('%',#{memberExtendFieldConfigEntity.colTitle},'%')


    AND t.col_name like concat('%',#{memberExtendFieldConfigEntity.colName},'%')


    AND t.prop_name like concat('%',#{memberExtendFieldConfigEntity.propName},'%')


    AND t.col_type = #{memberExtendFieldConfigEntity.colType}


    AND t.prop_type like concat('%',#{memberExtendFieldConfigEntity.propType},'%')


    AND t.is_form_require = #{memberExtendFieldConfigEntity.isFormRequire}


    AND t.validate_type = #{memberExtendFieldConfigEntity.validateType}


    AND t.form_type = #{memberExtendFieldConfigEntity.formType}


    AND t.limit_size = #{memberExtendFieldConfigEntity.limitSize}


    AND t.listdata_config = #{memberExtendFieldConfigEntity.listdataConfig}


    limit #{map.offset},#{map.rows}

SELECT COLUMN_NAME as name,
       COLUMN_TYPE as type
FROM information_schema.`COLUMNS`
WHERE TABLE_NAME = #{tableName}
  AND COLUMN_NAME = #{colName}
  and table_schema = (select database()) LIMIT 1

select id
from member_extend_field
where member_id = #{memberId}
